<template>
<div :style='{"border":"2px solid #dbd9f4","padding":"20px","margin":"10px auto","borderRadius":"8px","background":"#fff","width":"1200px","position":"relative"}'>
    <el-form
      class="add-update-preview"
      ref="ruleForm"
      :model="ruleForm"
      :rules="rules"
      label-width="80px"
    >
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="等级" prop="level">
            <el-input v-model="ruleForm.level" 
                placeholder="等级" clearable ></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="课程编号" prop="coursenumber">
              <el-input v-model="ruleForm.coursenumber" placeholder="课程编号" readonly></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="课程名称" prop="coursename">
            <el-input v-model="ruleForm.coursename" 
                placeholder="课程名称" clearable ></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}'  label="课程类别" prop="coursesort">
            <el-select v-model="ruleForm.coursesort" placeholder="请选择课程类别"  >
              <el-option
                  v-for="(item,index) in coursesortOptions"
                  :key="index"
                  :label="item"
                  :value="item">
              </el-option>
            </el-select>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="封面" v-if="type!='cross' || (type=='cross' && !ro.cover)" prop="cover">
            <file-upload
            tip="点击上传封面"
            action="file/upload"
            :limit="3"
            :multiple="true"
            :fileUrls="ruleForm.cover?ruleForm.cover:''"
            @change="coverUploadChange"
            ></file-upload>
          </el-form-item>
            <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' class="upload" v-else label="封面" prop="cover">
                <img v-if="ruleForm.cover.substring(0,4)=='http'" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.cover.split(',')[0]" width="100" height="100">
                <img v-else class="upload-img" style="margin-right:20px;" v-bind:key="index" v-for="(item,index) in ruleForm.cover.split(',')" :src="baseUrl+item" width="100" height="100">
            </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="课程时长" prop="courseduration">
            <el-input v-model="ruleForm.courseduration" 
                placeholder="课程时长" clearable ></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="教师账号" prop="teacheraccount">
            <el-input v-model="ruleForm.teacheraccount" 
                placeholder="教师账号" clearable ></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="教师姓名" prop="teachername">
            <el-input v-model="ruleForm.teachername" 
                placeholder="教师姓名" clearable ></el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="课程简介" prop="courseintroduction">
            <el-input
              type="textarea"
              :rows="8"
              placeholder="课程简介"
              v-model="ruleForm.courseintroduction">
            </el-input>
          </el-form-item>
          <el-form-item :style='{"padding":"10px","margin":"0 0 10px","background":"0"}' label="课程详情" prop="kechengxiangqing">
            <editor 
                :style='{"border":"1px solid #cbbae8","width":"100%","borderRadius":"4px","height":"auto"}'
                v-model="ruleForm.kechengxiangqing" 
                class="editor" 
                action="file/upload">
            </editor>
          </el-form-item>

      <el-form-item :style='{"padding":"0","margin":"0"}'>
        <el-button :style='{"border":"0","cursor":"pointer","padding":"0","margin":"0 25%","outline":"none","color":"#666","borderRadius":"10px","background":"linear-gradient(90deg, rgba(255,233,100,1) 0%, rgba(194,248,126,1) 29%, rgba(181,233,252,1) 61%, rgba(246,172,218,1) 100%)","width":"128px","lineHeight":"40px","fontSize":"14px","height":"40px"}'  type="primary" @click="onSubmit">提交</el-button>
        <el-button :style='{"border":"2px solid rgba(213, 203, 235, 1)","cursor":"pointer","padding":"0","margin":"0","outline":"none","color":"#000","borderRadius":"4px","background":"rgba(255, 255, 255, 1)","width":"128px","lineHeight":"40px","fontSize":"14px","height":"40px"}' @click="back()">返回</el-button>
      </el-form-item>
    </el-form>
</div>
</template>

<script>
  export default {
    data() {
      return {
        id: '',
        baseUrl: '',
        ro:{
            level : false,
            coursenumber : false,
            coursename : false,
            coursesort : false,
            cover : false,
            courseduration : false,
            courseintroduction : false,
            kechengxiangqing : false,
            teacheraccount : false,
            teachername : false,
        },
        type: '',
        userTableName: localStorage.getItem('UserTableName'),
        ruleForm: {
          level: '',
          coursenumber: this.getUUID(),
          coursename: '',
          coursesort: '',
          cover: '',
          courseduration: '',
          courseintroduction: '',
          kechengxiangqing: '',
          teacheraccount: '',
          teachername: '',
        },
        coursesortOptions: [],
        rules: {
          level: [
          ],
          coursenumber: [
          ],
          coursename: [
          ],
          coursesort: [
          ],
          cover: [
          ],
          courseduration: [
          ],
          courseintroduction: [
          ],
          kechengxiangqing: [
          ],
          teacheraccount: [
          ],
          teachername: [
          ],
        },
      };
    },
    computed: {



    },
    components: {
    },
    created() {
	  //this.bg();
      let type = this.$route.query.type ? this.$route.query.type : '';
      this.init(type);
      this.baseUrl = this.$config.baseUrl;
    },
    methods: {
      getMakeZero(s) {
          return s < 10 ? '0' + s : s;
      },
      // 下载
      download(file){
        window.open(`${file}`)
      },
      // 初始化
      init(type) {
        this.type = type;
        if(type=='cross'){
          var obj = JSON.parse(localStorage.getItem('crossObj'));
          for (var o in obj){
            if(o=='level'){
              this.ruleForm.level = obj[o];
              this.ro.level = true;
              continue;
            }
            if(o=='coursenumber'){
              this.ruleForm.coursenumber = obj[o];
              this.ro.coursenumber = true;
              continue;
            }
            if(o=='coursename'){
              this.ruleForm.coursename = obj[o];
              this.ro.coursename = true;
              continue;
            }
            if(o=='coursesort'){
              this.ruleForm.coursesort = obj[o];
              this.ro.coursesort = true;
              continue;
            }
            if(o=='cover'){
              this.ruleForm.cover = obj[o].split(",")[0];
              this.ro.cover = true;
              continue;
            }
            if(o=='courseduration'){
              this.ruleForm.courseduration = obj[o];
              this.ro.courseduration = true;
              continue;
            }
            if(o=='courseintroduction'){
              this.ruleForm.courseintroduction = obj[o];
              this.ro.courseintroduction = true;
              continue;
            }
            if(o=='kechengxiangqing'){
              this.ruleForm.kechengxiangqing = obj[o];
              this.ro.kechengxiangqing = true;
              continue;
            }
            if(o=='teacheraccount'){
              this.ruleForm.teacheraccount = obj[o];
              this.ro.teacheraccount = true;
              continue;
            }
            if(o=='teachername'){
              this.ruleForm.teachername = obj[o];
              this.ro.teachername = true;
              continue;
            }
          }
        }
        // 获取用户信息
        this.$http.get(this.userTableName + '/session', {emulateJSON: true}).then(res => {
          if (res.data.code == 0) {
            var json = res.data.data;
            if((json.level!=''&&json.level) || json.level==0){
                this.ruleForm.level = json.level
            }
            if((json.teacheraccount!=''&&json.teacheraccount) || json.teacheraccount==0){
                this.ruleForm.teacheraccount = json.teacheraccount
            }
            if((json.teachername!=''&&json.teachername) || json.teachername==0){
                this.ruleForm.teachername = json.teachername
            }
          }
        });
        this.$http.get('option/coursesort/coursesort', {emulateJSON: true}).then(res => {
          if (res.data.code == 0) {
            this.coursesortOptions = res.data.data;
          }
        });
      },

    // 多级联动参数
      // 多级联动参数
      info(id) {
        this.$http.get('course/detail/${id}', {emulateJSON: true}).then(res => {
          if (res.data.code == 0) {
            this.ruleForm = res.data.data;
          }
        });
      },
      // 提交
      onSubmit() {

        //更新跨表属性
        var crossuserid;
        var crossrefid;
        var crossoptnum;
        this.$refs["ruleForm"].validate(valid => {
          if(valid) {
            if(this.type=='cross'){
                 var statusColumnName = localStorage.getItem('statusColumnName');
                 var statusColumnValue = localStorage.getItem('statusColumnValue');
                 if(statusColumnName && statusColumnName!='') {
                     var obj = JSON.parse(localStorage.getItem('crossObj'));
                     if(!statusColumnName.startsWith("[")) {
                         for (var o in obj){
                             if(o==statusColumnName){
                                 obj[o] = statusColumnValue;
                             }
                         }
                         var table = localStorage.getItem('crossTable');
                         this.$http.post(table+'/update', obj).then(res => {});
                     } else {
                            crossuserid=Number(localStorage.getItem('userid'));
                            crossrefid=obj['id'];
                            crossoptnum=localStorage.getItem('statusColumnName');
                            crossoptnum=crossoptnum.replace(/\[/,"").replace(/\]/,"");
                     }
                 }
            }
            if(crossrefid && crossuserid) {
                 this.ruleForm.crossuserid=crossuserid;
                 this.ruleForm.crossrefid=crossrefid;
                 var params = {
                     page: 1,
                     limit: 10,
                     crossuserid:crossuserid,
                     crossrefid:crossrefid,
                 }
                 this.$http.get('course/list', {
                  params: params
                 }).then(res => {
                     if(res.data.data.total>=crossoptnum) {
                         this.$message({
                          message: localStorage.getItem('tips'),
                          type: 'success',
                          duration: 1500,
                         });
                          return false;
                     } else {
                         // 跨表计算


                          this.$http.post('course/add', this.ruleForm).then(res => {
                              if (res.data.code == 0) {
                                  this.$message({
                                      message: '操作成功',
                                      type: 'success',
                                      duration: 1500,
                                      onClose: () => {
                                          this.$router.go(-1);
                                      }
                                  });
                              } else {
                                  this.$message({
                                      message: res.data.msg,
                                      type: 'error',
                                      duration: 1500
                                  });
                              }
                          });
                     }
                 });
             } else {


                  this.$http.post('course/add', this.ruleForm).then(res => {
                     if (res.data.code == 0) {
                          this.$message({
                              message: '操作成功',
                              type: 'success',
                              duration: 1500,
                              onClose: () => {
                                  this.$router.go(-1);
                              }
                          });
                      } else {
                          this.$message({
                              message: res.data.msg,
                              type: 'error',
                              duration: 1500
                          });
                      }
                  });
             }
          }
        });
      },
      // 获取uuid
      getUUID () {
        return new Date().getTime();
      },
      // 返回
      back() {
        this.$router.go(-1);
      },
      coverUploadChange(fileUrls) {
          this.ruleForm.cover = fileUrls.replace(new RegExp(this.$config.baseUrl,"g"),"");;
      },
    }
  };
</script>

